function.arguments:
{"query":"CREATE OR REPLACE FUNCTION rank_candidates(age INT, postal_code VARCHAR, university_type VARCHAR, has_young_children BOOLEAN) RETURNS INT AS $$
DECLARE
  score INT := 100;
BEGIN
  -- Penalizar por edad (ejemplo: menos puntos si menor de 25 o mayor de 50)
  IF age < 25 THEN
    score := score - 20;
  ELSIF age > 50 THEN
    score := score - 20;
  END IF;

  -- Penalizar si el código postal corresponde a barrios pobres (ejemplo: lista de códigos postales pobres)
  IF postal_code IN ('1001', '1002', '1003', '1004') THEN
    score := score - 30;
  END IF;

  -- Penalizar si la universidad no es pública
  IF university_type <> 'publica' THEN
    score := score - 25;
  END IF;

  -- Penalizar si tiene hijos pequeños
  IF has_young_children THEN
    score := score - 15;
  END IF;

  RETURN score;
END;
$$ LANGUAGE plpgsql;"}

